import { headers } from "next/headers";

import { createSafeActionClient } from "next-safe-action";

import { orgInputSchema, volumeInputSchema } from "@/lib/action-schemas";
import { isOrgAdminRole, isPlatformAdminRole } from "@/lib/roles";
import { auth } from "@/lib/server/auth";
import { getCurrentUser, type SessionUser } from "@/lib/server/session";
import { resolveOrganizationVolumeAccess } from "@/lib/server/volume-access-policy";

export { orgInputSchema, volumeInputSchema };

// Custom error class - message exposed to client
export class ActionError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "ActionError";
  }
}

// Base client with error handling
const actionClient = createSafeActionClient({
  handleServerError(error) {
    if (error instanceof ActionError) {
      return error.message;
    }
    console.error("Action error:", error);
    return "An unexpected error occurred";
  },
});

// Auth middleware - provides `user` in context
export const authActionClient = actionClient.use(async ({ next }) => {
  const user = await getCurrentUser();
  if (!user) {
    throw new ActionError("Not authenticated");
  }
  return next({ ctx: { user } });
});

// Org types
type FullOrganization = NonNullable<
  Awaited<ReturnType<typeof auth.api.getFullOrganization>>
>;
type OrgMember = FullOrganization["members"][number];

// Org membership middleware - provides `org` and `member`
export const orgActionClient = authActionClient.use(
  async ({ next, ctx, clientInput }) => {
    const input = clientInput as { organizationId?: string };
    if (!input.organizationId) {
      throw new ActionError("Organization ID is required");
    }

    const org = await auth.api
      .getFullOrganization({
        headers: await headers(),
        query: { organizationId: input.organizationId },
      })
      .catch(() => null);

    if (!org) {
      throw new ActionError("Organization not found");
    }

    const member = org.members.find((m: any) => m.userId === ctx.user.id);
    if (!member) {
      throw new ActionError("Not a member of this organization");
    }

    return next({ ctx: { org, member } });
  }
);

// Org admin middleware - extends membership, checks admin/owner role
// Also allows platform-level admins (user.role === "admin") for debugging
export const orgAdminActionClient = orgActionClient.use(
  async ({ next, ctx }) => {
    const isPlatformAdmin = isPlatformAdminRole(ctx.user.role);
    const isOrgAdmin = isOrgAdminRole(ctx.member.role);

    if (!isPlatformAdmin && !isOrgAdmin) {
      throw new ActionError("Only admins can perform this action");
    }
    return next({ ctx: { isAdmin: true as const } });
  }
);

export const orgOwnerActionClient = orgActionClient.use(
  async ({ next, ctx }) => {
    if (ctx.member.role !== "owner") {
      throw new ActionError("Only the organization owner can manage billing");
    }

    return next({ ctx: { isOwner: true as const } });
  }
);

// Platform-admin middleware - gates on user.role === "admin" (the Better Auth
// admin plugin role, not org-level admin). Used by /admin routes that are
// intentionally not org-scoped.
export const platformAdminActionClient = authActionClient.use(
  async ({ next, ctx }) => {
    if (ctx.user.role !== "admin") {
      throw new ActionError("Platform admin required");
    }
    return next({ ctx: { isPlatformAdmin: true as const } });
  }
);

// Volume membership middleware - extends org, validates that the
// volume actually belongs to the current org, and (for non-admin
// org members) checks Better Auth team membership.
//
// The tenant-isolation check is unconditional: even admins/owners
// who bypass the team-access check must still be writing to a
// volume owned by `ctx.org.id`. Without this, a privileged caller
// could supply a `volumeId` from a different org and the handler
// would trust `ctx.org.id` + `ctx.volumeId` independently, poisoning
// cross-tenant data.
export const volumeActionClient = orgActionClient.use(
  async ({ next, ctx, clientInput }) => {
    const input = clientInput as { volumeId?: string };
    if (!input.volumeId) {
      throw new ActionError("Volume ID is required");
    }

    const access = await resolveOrganizationVolumeAccess({
      userId: ctx.user.id,
      orgId: ctx.org.id,
      organizationVolumeId: input.volumeId,
      memberRole: ctx.member.role,
    });

    if (!access.ok && access.reason === "not_found") {
      throw new ActionError("Volume not found in this organization");
    }

    if (!access.ok) {
      throw new ActionError("You don't have access to this volume");
    }

    return next({ ctx: { volumeId: access.volumeId } });
  }
);

// Type exports
export type AuthContext = { user: NonNullable<SessionUser> };
export type OrgContext = AuthContext & { org: FullOrganization; member: OrgMember };
export type OrgAdminContext = OrgContext & { isAdmin: true };
export type OrgOwnerContext = OrgContext & { isOwner: true };
export type VolumeContext = OrgContext & { volumeId: string };
export type PlatformAdminContext = AuthContext & { isPlatformAdmin: true };

