import { and, eq } from "drizzle-orm";

import { db } from "@/db";
import { organizationVolumes } from "@/db/schemas/organization-volumes.schema";
import { isVolumeMember } from "@/features/volume-access/queries";
import { isOrgAdminRole } from "@/lib/roles";

type VolumeAccessResult =
  | { ok: true; volumeId: string; teamId: string | null }
  | { ok: false; reason: "not_found" | "no_team_access" };

export async function resolveOrganizationVolumeAccess(params: {
  userId: string;
  orgId: string;
  organizationVolumeId: string;
  memberRole?: string | null;
}): Promise<VolumeAccessResult> {
  const binding = await db.query.organizationVolumes.findFirst({
    where: and(
      eq(organizationVolumes.id, params.organizationVolumeId),
      eq(organizationVolumes.organizationId, params.orgId)
    ),
    columns: { id: true, teamId: true },
  });

  if (!binding) {
    return { ok: false, reason: "not_found" };
  }

  if (!isOrgAdminRole(params.memberRole)) {
    const hasAccess = await isVolumeMember({
      userId: params.userId,
      organizationId: params.orgId,
      organizationVolumeId: binding.id,
    });

    if (!hasAccess) {
      return { ok: false, reason: "no_team_access" };
    }
  }

  return { ok: true, volumeId: binding.id, teamId: binding.teamId };
}

