export const ORG_ADMIN_ROLES = ["admin", "owner"] as const;
export const PLATFORM_ADMIN_ROLE = "admin";

export function isOrgAdminRole(role: string | null | undefined) {
  return role === "admin" || role === "owner";
}

export function isPlatformAdminRole(role: string | null | undefined) {
  return role === PLATFORM_ADMIN_ROLE;
}

