import "server-only";

import { countSeatLearners } from "@/features/organization/learner-roles";
import { getOrgLifecycleState } from "@/features/organization/queries";

import { getPendingLearnerInvitationCount } from "./counts";
import type { EntitlementKey } from "./entitlements";
import { getOrganizationBilling } from "./mirror";

export async function getOrgEntitlements(
  organizationId: string
): Promise<EntitlementKey[]> {
  const billing = await getOrganizationBilling(organizationId);
  return billing?.entitlements ?? [];
}

export async function orgHasEntitlement(
  organizationId: string,
  key: EntitlementKey
): Promise<boolean> {
  const entitlements = await getOrgEntitlements(organizationId);
  return entitlements.includes(key);
}

export type SeatCheckResult =
  | { allowed: true }
  | { allowed: false; reason: "preview" }
  | { allowed: false; reason: "billing_required" }
  | {
      allowed: false;
      reason: "no_seats";
      entitled: number;
      currentMembers: number;
      currentPending: number;
      requestedDelta: number;
    };

// Read-once snapshot of the inputs the policy depends on. Captured by
// computeSeatBudget so each entry point applies its own delta against
// a consistent set of counts (no per-call re-reads).
type SeatBudgetSnapshot =
  | { kind: "preview" }
  | { kind: "unlimited" }
  | { kind: "billing_required" }
  | {
      kind: "ready";
      entitled: number;
      currentMembers: number;
      currentPending: number;
    };

// Reads lifecycle + billing + counts in parallel and short-circuits in
// the order ADR-0002 documents:
//   1. preview lifecycle  → 'preview' (overrides everything below).
//   2. unlimited-seats entitlement → 'unlimited' (bypass headroom).
//   3. missing stripeSubscriptionId → 'billing_required'.
//   4. otherwise → 'ready' with the numbers each entry point uses.
async function computeSeatBudget(params: {
  orgId: string;
}): Promise<SeatBudgetSnapshot> {
  const [lifecycleState, billing, currentMembers, currentPending] =
    await Promise.all([
      getOrgLifecycleState(params.orgId),
      getOrganizationBilling(params.orgId),
      countSeatLearners({ orgId: params.orgId }),
      getPendingLearnerInvitationCount(params.orgId),
    ]);

  if (lifecycleState === "preview") {
    return { kind: "preview" };
  }
  if (billing?.entitlements.includes("unlimited-seats")) {
    return { kind: "unlimited" };
  }
  if (!billing?.stripeSubscriptionId) {
    return { kind: "billing_required" };
  }
  return {
    kind: "ready",
    entitled: billing.seatCount,
    currentMembers,
    currentPending,
  };
}

// All four intent-specific entry points share the same applyDelta
// helper. The delta encodes the entry point's specific budget question:
//   - invite-batch        : delta = batchSize, count pending
//   - invite-acceptance   : delta = 0, count pending
//                           (the pending row already covers the seat;
//                            entitled must still cover members+pending)
//   - scorm provision     : delta = 1, count pending
//   - role promotion      : delta = 1, count pending
//
// Every entry point counts pending — see ADR-0002. The boolean
// `includePending` from the old API is gone.
function applyDelta(
  snapshot: SeatBudgetSnapshot,
  requestedDelta: number
): SeatCheckResult {
  if (snapshot.kind === "preview") {
    return { allowed: false, reason: "preview" };
  }
  if (snapshot.kind === "unlimited") {
    return { allowed: true };
  }
  if (snapshot.kind === "billing_required") {
    return { allowed: false, reason: "billing_required" };
  }
  const total = snapshot.currentMembers + snapshot.currentPending + requestedDelta;
  if (total > snapshot.entitled) {
    return {
      allowed: false,
      reason: "no_seats",
      entitled: snapshot.entitled,
      currentMembers: snapshot.currentMembers,
      currentPending: snapshot.currentPending,
      requestedDelta,
    };
  }
  return { allowed: true };
}

// Bulk-invite: succeed iff currentMembers + currentPending + batchSize
// ≤ entitled. Per-batch consistency means a single read covers the
// whole invite batch; the batch action is wrapped in withOrgSeatLock
// so two concurrent invites cannot both pass this check on stale data.
export async function checkInviteCapacityForBatch(params: {
  orgId: string;
  batchSize: number;
}): Promise<SeatCheckResult> {
  const snapshot = await computeSeatBudget({ orgId: params.orgId });
  return applyDelta(snapshot, params.batchSize);
}

// Invite acceptance: a pending invitation already reserves a seat in
// our model, so the delta is 0. The check still fails if entitlement
// has shrunk below currentMembers + currentPending (the post-downgrade
// over-committed state from ADR-0002).
export async function checkInviteAcceptance(params: {
  orgId: string;
}): Promise<SeatCheckResult> {
  const snapshot = await computeSeatBudget({ orgId: params.orgId });
  return applyDelta(snapshot, 0);
}

// SCORM auto-provision: a single new learner seat. Under ADR-0002 this
// can now be blocked by pending invitations — that is a documented
// behavior change (was: succeeded as long as members < entitled).
export async function checkScormProvisionCapacity(params: {
  orgId: string;
}): Promise<SeatCheckResult> {
  const snapshot = await computeSeatBudget({ orgId: params.orgId });
  return applyDelta(snapshot, 1);
}

// Admin → member role promotion: one fewer admin, one more member.
// Under ADR-0002 this can now be blocked by pending invitations — same
// behavior change as SCORM provision.
export async function checkRolePromotionToMember(params: {
  orgId: string;
}): Promise<SeatCheckResult> {
  const snapshot = await computeSeatBudget({ orgId: params.orgId });
  return applyDelta(snapshot, 1);
}

