import "server-only";

import { and, count, eq, gt } from "drizzle-orm";

import { db } from "@/db";
import { invitations, members, users } from "@/db/schemas/auth.schema";
import { countSeatLearners } from "@/features/organization/learner-roles";
import { getOrganizationBilling } from "./mirror";

// Aggregate counts of org membership state. Used by the seat policy and
// by the owner billing UI to display "X of Y seats used" — kept separate
// from the mirror module because the data lives on the auth tables, not
// on organization_billing. Seat-learner counting now lives in
// features/organization/learner-roles.ts (ADR-0001 ownership rule).

export async function getPendingLearnerInvitationCount(organizationId: string) {
  // Effectively-expired pending rows would otherwise bloat the seat count.
  // Better Auth's `cancelPendingInvitationsOnReInvite` cleans them up on
  // re-invite, but until then they should not consume budget.
  const [result] = await db
    .select({ count: count() })
    .from(invitations)
    .where(
      and(
        eq(invitations.organizationId, organizationId),
        eq(invitations.role, "member"),
        eq(invitations.status, "pending"),
        gt(invitations.expiresAt, new Date())
      )
    );

  return result?.count ?? 0;
}

// Email lookups for bulk-invite partitioning. Returned keys are lowercased
// so the invite action can do case-insensitive membership checks against
// admin-pasted input without re-normalizing per email.
//
// These include all roles (owner/admin/member), not just learners, so that
// existing admins/owners are detected as alreadyMember instead of being
// counted as net-new learner invites against the seat budget.

export async function getOrganizationMemberEmails(organizationId: string) {
  const rows = await db
    .select({ email: users.email })
    .from(members)
    .innerJoin(users, eq(members.userId, users.id))
    .where(eq(members.organizationId, organizationId));

  return new Set(rows.map((row) => row.email.toLowerCase()));
}

// Returns a Map from lowercased email to the invitation's stored role, so
// the invite action can detect role conflicts (e.g. a pending admin invite
// re-invited as a learner) and refuse to silently refresh under a mismatched
// role. Better Auth's resend path does not update the stored role.
export async function getPendingInvitationRoles(organizationId: string) {
  // Filter out effectively-expired rows so the bulk-invite classifier
  // doesn't see them as live conflicts. With this filter in place,
  // `cancelPendingInvitationsOnReInvite` can safely supersede stale rows
  // without surprising the classifier.
  const rows = await db
    .select({ email: invitations.email, role: invitations.role })
    .from(invitations)
    .where(
      and(
        eq(invitations.organizationId, organizationId),
        eq(invitations.status, "pending"),
        gt(invitations.expiresAt, new Date())
      )
    );

  const map = new Map<string, string>();
  for (const row of rows) {
    if (row.role) map.set(row.email.toLowerCase(), row.role);
  }
  return map;
}

export async function getSeatAvailability(organizationId: string) {
  const [billing, learnerCount, pendingInvitationCount] = await Promise.all([
    getOrganizationBilling(organizationId),
    countSeatLearners({ orgId: organizationId }),
    getPendingLearnerInvitationCount(organizationId),
  ]);

  const seatCount = billing?.seatCount ?? 0;

  return {
    seatCount,
    learnerCount,
    pendingInvitationCount,
    availableSeats: seatCount - learnerCount - pendingInvitationCount,
  };
}

export async function hasAvailableSeat(organizationId: string) {
  const availability = await getSeatAvailability(organizationId);
  return availability.availableSeats > 0;
}

