import { cache } from "react";
import { and, count, eq, notInArray } from "drizzle-orm";

import { db } from "@/db";
import { members, teamMembers } from "@/db/schemas/auth.schema";
import { organizationVolumes } from "@/db/schemas/organization-volumes.schema";
import { ORG_ADMIN_ROLES } from "@/lib/roles";

// Two deliberately distinct predicate spaces — see ADR-0001 (ownership
// rule for cross-feature primitives). Collapsing them into one fuzzy
// "is learner" predicate would hide a real distinction: a user can
// occupy a seat in the org's plan without being a member of any
// volume's cohort, and (in admin-preview contexts) vice versa.
//
//   seatLearner       — billing/seat-math concept; gated by
//                       members.role = 'member' for the org. Pending
//                       invitations are NOT seat learners; they live
//                       on a separate "pending" budget axis (see
//                       features/billing/policy.ts and ADR-0002).
//
//   volumeCohortLearner — dashboard/cohort-analytics concept; gated
//                         by team_members + members.role ∉
//                         ORG_ADMIN_ROLES for the org. Excludes
//                         admins/owners and requires explicit team
//                         membership for the volume.
//
// Every volume-cohort helper takes orgId alongside organizationVolumeId
// so cross-tenant mistakes are hard to write at the callsite.

// --- Seat learner predicates ---

async function fetchSeatLearnerCount(params: { orgId: string }) {
  const [result] = await db
    .select({ count: count() })
    .from(members)
    .where(
      and(
        eq(members.organizationId, params.orgId),
        eq(members.role, "member")
      )
    );

  return result?.count ?? 0;
}

export const countSeatLearners = cache(fetchSeatLearnerCount);

// --- Volume-cohort learner predicates ---

export function volumeCohortLearnerIdsSubquery(params: {
  orgId: string;
  organizationVolumeId: string;
}) {
  return db
    .select({ userId: teamMembers.userId })
    .from(teamMembers)
    .innerJoin(
      organizationVolumes,
      eq(organizationVolumes.teamId, teamMembers.teamId)
    )
    .innerJoin(
      members,
      and(
        eq(members.userId, teamMembers.userId),
        eq(members.organizationId, params.orgId)
      )
    )
    .where(
      and(
        eq(organizationVolumes.id, params.organizationVolumeId),
        eq(organizationVolumes.organizationId, params.orgId),
        notInArray(members.role, [...ORG_ADMIN_ROLES])
      )
    );
}

async function fetchVolumeCohortLearnerIds(params: {
  orgId: string;
  organizationVolumeId: string;
}): Promise<string[]> {
  const rows = await volumeCohortLearnerIdsSubquery(params);
  return rows.map((row) => row.userId);
}

export const getVolumeCohortLearnerIds = cache(fetchVolumeCohortLearnerIds);

async function fetchIsVolumeCohortLearner(params: {
  orgId: string;
  organizationVolumeId: string;
  userId: string;
}): Promise<boolean> {
  const rows = await db
    .select({ userId: teamMembers.userId })
    .from(teamMembers)
    .innerJoin(
      organizationVolumes,
      eq(organizationVolumes.teamId, teamMembers.teamId)
    )
    .innerJoin(
      members,
      and(
        eq(members.userId, teamMembers.userId),
        eq(members.organizationId, params.orgId)
      )
    )
    .where(
      and(
        eq(teamMembers.userId, params.userId),
        eq(organizationVolumes.id, params.organizationVolumeId),
        eq(organizationVolumes.organizationId, params.orgId),
        notInArray(members.role, [...ORG_ADMIN_ROLES])
      )
    )
    .limit(1);

  return rows.length > 0;
}

export const isVolumeCohortLearner = cache(fetchIsVolumeCohortLearner);

