// Pure validation + diff for the per-member volume access editor.
// Kept apart from the server action so it can be tested without
// drizzle/db mocking — the action orchestrates db reads/writes around it.

export type MemberVolumeAccessInput = {
  targetMember: { role: string } | null;
  orgVolumes: Array<{ id: string; teamId: string | null }>;
  currentTeamIds: string[];
  requestedVolumeIds: string[];
};

export type MemberVolumeAccessDiff = {
  additions: string[];
  removals: string[];
};

export class MemberVolumeAccessError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "MemberVolumeAccessError";
  }
}

export function computeMemberVolumeAccessDiff(
  input: MemberVolumeAccessInput
): MemberVolumeAccessDiff {
  const { targetMember, orgVolumes, currentTeamIds, requestedVolumeIds } =
    input;

  if (!targetMember) {
    throw new MemberVolumeAccessError(
      "User is not a member of this organization"
    );
  }

  if (targetMember.role !== "member") {
    throw new MemberVolumeAccessError(
      "Admins access all volumes — change role instead"
    );
  }

  const orgVolumeIds = new Set(orgVolumes.map((v) => v.id));
  for (const id of requestedVolumeIds) {
    if (!orgVolumeIds.has(id)) {
      throw new MemberVolumeAccessError(
        "One of the selected volumes is not in this organization"
      );
    }
  }

  const teamIdByVolumeId = new Map<string, string>();
  for (const v of orgVolumes) {
    if (v.teamId) teamIdByVolumeId.set(v.id, v.teamId);
  }
  for (const id of requestedVolumeIds) {
    if (!teamIdByVolumeId.has(id)) {
      throw new MemberVolumeAccessError(
        "One of the selected volumes is missing its team — contact support to repair it"
      );
    }
  }

  const currentSet = new Set(currentTeamIds);
  const targetSet = new Set(
    requestedVolumeIds.map((id) => teamIdByVolumeId.get(id)!)
  );

  const additions: string[] = [];
  for (const teamId of targetSet) {
    if (!currentSet.has(teamId)) additions.push(teamId);
  }
  const removals: string[] = [];
  for (const teamId of currentSet) {
    if (!targetSet.has(teamId)) removals.push(teamId);
  }

  return { additions, removals };
}

// All teamIds that belong to this org's volumes — used by the action
// to scope the team_members read so cross-org rows are never visible
// or deletable from this surface.
export function orgTeamIds(
  orgVolumes: Array<{ teamId: string | null }>
): string[] {
  return orgVolumes
    .map((v) => v.teamId)
    .filter((id): id is string => Boolean(id));
}

