// Stable Better Auth error messages, kept as literals rather than imported
// because ORGANIZATION_ERROR_CODES isn't publicly re-exported by the plugin
// entrypoint. Source: better-auth/plugins/organization/error-codes.
const BETTER_AUTH_ALREADY_MEMBER_MESSAGE =
  "User is already a member of this organization";

const INVITE_CONCURRENCY = 5;

async function mapWithConcurrency<T, R>(
  items: T[],
  limit: number,
  fn: (item: T) => Promise<R>
): Promise<PromiseSettledResult<R>[]> {
  const results: PromiseSettledResult<R>[] = new Array(items.length);
  let cursor = 0;
  const worker = async () => {
    while (true) {
      const i = cursor++;
      if (i >= items.length) return;
      try {
        results[i] = { status: "fulfilled", value: await fn(items[i]) };
      } catch (reason) {
        results[i] = { status: "rejected", reason };
      }
    }
  };
  const workers = Array.from(
    { length: Math.min(limit, items.length) },
    worker
  );
  await Promise.all(workers);
  return results;
}

