      // also receive the new volume.
    }

    await db
      .update(organizationVolumes)
      .set({ learnerSyncDecidedAt: new Date() })
      .where(eq(organizationVolumes.id, organizationVolumeId));

    revalidatePath(`/org/${orgSlug}`, "layout");
