// --- Resend invitation ---

const resendInvitationSchema = orgInputSchema.extend({
  orgSlug: z.string(),
  invitationId: z.string(),
});

// Refreshes the invitation expiry in place (Better Auth's `resend: true`
// path) and re-sends the email with the current invitation_volumes
// snapshot. Replaces the prior client-side cancel-then-re-invite flow,
// which silently dropped the volume scope and predated the email
// timing fix.
export const resendInvitation = orgAdminActionClient
  .inputSchema(resendInvitationSchema)
  .action(async ({ parsedInput }) => {
    const { organizationId, orgSlug, invitationId } = parsedInput;

    const [row] = await db
      .select({
        id: invitations.id,
        email: invitations.email,
        role: invitations.role,
        organizationId: invitations.organizationId,
        status: invitations.status,
        expiresAt: invitations.expiresAt,
      })
      .from(invitations)
      .where(eq(invitations.id, invitationId))
      .limit(1);

    if (!row || row.organizationId !== organizationId) {
      throw new ActionError("Invitation not found in this organization");
    }
    if (!row.role) {
      throw new ActionError("Invitation has no role; cannot resend");
    }

    // Gate at the action boundary, not just in the table UI. A stale
    // client (page open across an expiry) could otherwise trigger
    // resend on a non-pending row, where Better Auth's resend lookup
    // would silently create a fresh invitation while we'd email the
    // old expired link.
    const effective = effectiveInvitationStatus(row);
    if (effective !== "pending") {
      throw new ActionError(
        `Cannot resend a${effective === "expired" ? "n" : ""} ${effective} invitation. Use the Send Invitations form to invite this person again.`
      );
    }

    const headers = await getHeaders();
    const created = await auth.api.createInvitation({
      body: {
        email: row.email,
        role: row.role as "member" | "admin",
        organizationId,
        resend: true,
      },
      headers,
    });

    // Defense in depth against the race window between our SELECT and
    // Better Auth's own pending-row lookup. If BA created a new row
    // instead of refreshing the one we validated, sending for our
    // input invitationId would email a now-superseded link. Surface
    // the race; admin refreshes and resends from the new row.
    const returnedId = (created as { id?: string } | null)?.id;
    if (returnedId && returnedId !== invitationId) {
      throw new ActionError(
        "Invitation state changed during resend. Refresh and try again."
      );
    }

    // Hook is a no-op; send from app code so the email reflects the
    // current invitation_volumes snapshot (not pre-write or stale).
    await sendInvitationEmailForId(invitationId);

    revalidatePath(`/org/${orgSlug}/people`);
    return { success: true };
  });

