"use server";

import { headers } from "next/headers";
import { z } from "zod";

import { withOrgSeatLock } from "@/features/billing/locks";
import { seatCheckErrorMessage } from "@/features/billing/messages";
import { checkInviteAcceptance } from "@/features/billing/policy";
import { getInvitationDetails } from "@/features/organization/invitation-queries";
import { effectiveInvitationStatus } from "@/features/organization/invitation-status";
import { ActionError, authActionClient } from "@/lib/action-client";
import { auth } from "@/lib/server/auth";

const invitationActionSchema = z.object({
  invitationId: z.string(),
  organizationId: z.string(),
  organizationSlug: z.string(),
});

// Re-validates state at the action boundary as defense-in-depth against
// page-render → submit races. The invite page already prevalidates on
// every render; client-side router.refresh() after a thrown ActionError
// is what produces the truthful page state for the user.
async function loadInvitationOrThrow(
  invitationId: string,
  expectedOrganizationId: string
) {
  const invitation = await getInvitationDetails(invitationId);
  if (!invitation || invitation.organizationId !== expectedOrganizationId) {
    throw new ActionError("This invitation is no longer available");
  }
  const effective = effectiveInvitationStatus(invitation);
  if (effective === "expired") {
    throw new ActionError("This invitation has expired");
  }
  if (effective === "accepted") {
    throw new ActionError("This invitation was already accepted");
  }
  if (effective === "canceled") {
    throw new ActionError("This invitation was canceled");
  }
  if (effective === "rejected") {
    throw new ActionError("This invitation was already declined");
  }
  return invitation;
}

async function assertSessionMatchesInvitee(
  headersList: Headers,
  inviteEmail: string
) {
  const session = await auth.api
    .getSession({ headers: headersList })
    .catch(() => null);
  if (
    !session ||
    session.user.email.toLowerCase() !== inviteEmail.toLowerCase()
  ) {
    throw new ActionError("This invitation is for a different email");
  }
}

export const acceptOrganizationInvitation = authActionClient
  .inputSchema(invitationActionSchema)
  .action(async ({ parsedInput }) => {
    const { invitationId, organizationId, organizationSlug } = parsedInput;
    const invitation = await loadInvitationOrThrow(invitationId, organizationId);

    const headersList = await headers();
    await assertSessionMatchesInvitee(headersList, invitation.email);

    const acceptInvitation = async () => {
      if (invitation.role === "member") {
        const check = await checkInviteAcceptance({ orgId: organizationId });
        if (!check.allowed) {
          // accept_invite context: the invitee sees this; they have no
          // power to fix billing or cancel pending invitations.
          throw new ActionError(seatCheckErrorMessage(check, "accept_invite"));
        }
      }

      await auth.api.acceptInvitation({
        headers: headersList,
        body: { invitationId },
      });
    };

    try {
      if (invitation.role === "member") {
        await withOrgSeatLock(organizationId, acceptInvitation);
      } else {
        await acceptInvitation();
      }
    } catch (error) {
      if (error instanceof ActionError) {
        throw error;
      }
      throw new ActionError(
        error instanceof Error
          ? error.message
          : "Failed to accept the invitation"
      );
    }

    await auth.api.setActiveOrganization({
      headers: headersList,
      body: {
        organizationId,
        organizationSlug,
      },
    });

    return { success: true };
  });

export const rejectOrganizationInvitation = authActionClient
  .inputSchema(invitationActionSchema)
  .action(async ({ parsedInput }) => {
    const { invitationId, organizationId } = parsedInput;
    const invitation = await loadInvitationOrThrow(invitationId, organizationId);

    const headersList = await headers();
    await assertSessionMatchesInvitee(headersList, invitation.email);

    try {
      await auth.api.rejectInvitation({
        headers: headersList,
        body: { invitationId },
      });
    } catch (error) {
      throw new ActionError(
        error instanceof Error
          ? error.message
          : "Failed to decline the invitation"
      );
    }

    return { success: true };
  });

