import {
  getCachedFullOrganization,
  getRequiredCurrentUser,
} from "@/lib/server/session";

/**
 * Owner gate for the (owner) route group.
 *
 * Same model as (admin): fresh session check at this boundary (parent
 * layouts can be stale per App Router preservation semantics), trust
 * parent for structural org membership. This layer enforces only the
 * incremental owner-only role check (no admin or platform-admin bypass —
 * billing is owner-only).
 */
export default async function OwnerLayout({
  children,
  params,
}: {
  children: React.ReactNode;
  params: Promise<{ orgSlug: string }>;
}) {
  const { orgSlug } = await params;

  const user = await getRequiredCurrentUser();
  const org = await getCachedFullOrganization(orgSlug);
  const member = org?.members.find((m: any) => m.userId === user.id);

  if (!member || member.role !== "owner") {
    forbidden();
  }

  return <>{children}</>;
}

