import { ColumnDef } from "@tanstack/react-table";
import { MoreHorizontal } from "lucide-react";

import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "@/components/ui/tooltip";

export type OrgMember = {
  memberId: string;
  userId: string;
  name: string | null;
  email: string;
  image: string | null;
  role: string;
  accessibleVolumeIds: string[];
};

export type OrgVolumeRef = {
  id: string;
  label: string;
};

export function getOrgMembersColumns({
  currentUserId,
  orgVolumes,
  onManageAccess,
  onChangeRole,
  onRemove,
}: {
  currentUserId: string;
  orgVolumes: OrgVolumeRef[];
  onManageAccess: (member: OrgMember) => void;
  onChangeRole: (memberId: string, newRole: "member" | "admin") => void;
  onRemove: (memberId: string) => void;
}): ColumnDef<OrgMember>[] {
  const labelById = new Map(orgVolumes.map((v) => [v.id, v.label]));

  return [
    {
      accessorKey: "name",
      header: "Name",
      cell: ({ row }) => (
        <div className="flex items-center gap-3">
          <Avatar className="size-8">
            <AvatarImage src={row.original.image || undefined} />
            <AvatarFallback>
              {row.original.name?.[0]?.toUpperCase() ||
                row.original.email[0].toUpperCase()}
            </AvatarFallback>
          </Avatar>
          <span className="font-medium">{row.original.name || "—"}</span>
        </div>
      ),
    },
    {
      accessorKey: "email",
      header: "Email",
      cell: ({ row }) => (
        <span className="text-muted-foreground">{row.original.email}</span>
      ),
    },
    {
      accessorKey: "role",
      header: "Role",
      cell: ({ row }) => {
        const role = row.original.role;
        return (
          <Badge variant={role === "owner" ? "default" : "secondary"}>
            {role}
          </Badge>
        );
      },
    },
    {
      id: "access",
      header: "Volume access",
      cell: ({ row }) => (
        <VolumeAccessBadge
          member={row.original}
          orgVolumes={orgVolumes}
          labelById={labelById}
        />
      ),
    },
    {
      id: "actions",
      cell: ({ row }) => {
        const member = row.original;
        const isCurrentUser = member.userId === currentUserId;
        const isOwner = member.role === "owner";

        if (isCurrentUser || isOwner) return null;

        return (
          <div className="flex items-center justify-end">
            <DropdownMenu>
              <DropdownMenuTrigger
                render={
                  <Button
                    variant="ghost"
                    size="icon"
                    aria-label={`Open actions for ${member.email}`}
                  />
                }
              >
                <MoreHorizontal className="size-4" />
              </DropdownMenuTrigger>
              <DropdownMenuContent align="end">
                {member.role === "member" && (
                  <DropdownMenuItem onClick={() => onManageAccess(member)}>
                    Manage access
                  </DropdownMenuItem>
                )}
                <DropdownMenuItem
                  onClick={() =>
                    onChangeRole(
                      member.memberId,
                      member.role === "admin" ? "member" : "admin"
                    )
                  }
                >
                  {member.role === "admin"
                    ? "Demote to learner"
                    : "Promote to admin"}
                </DropdownMenuItem>
                <DropdownMenuSeparator />
                <DropdownMenuItem
                  className="text-destructive focus:text-destructive"
                  onClick={() => onRemove(member.memberId)}
                >
                  Remove from organization
                </DropdownMenuItem>
              </DropdownMenuContent>
            </DropdownMenu>
          </div>
        );
      },
    },
  ];
}

function VolumeAccessBadge({
  member,
  orgVolumes,
  labelById,
}: {
  member: OrgMember;
  orgVolumes: OrgVolumeRef[];
  labelById: Map<string, string>;
}) {
  if (member.role !== "member") {
    return (
      <Badge variant="outline" className="text-muted-foreground">
        All (admin)
      </Badge>
    );
  }

  const total = orgVolumes.length;
  const accessible = member.accessibleVolumeIds.length;
  const isAll = total > 0 && accessible === total;
  const labels = member.accessibleVolumeIds
    .map((id) => labelById.get(id))
    .filter((label): label is string => Boolean(label));

  const text =
    total === 0
      ? "No volumes yet"
      : isAll
        ? `All (${total})`
        : `${accessible} of ${total}`;

  if (accessible === 0) {
    return (
      <Badge variant="outline" className="text-muted-foreground">
        {text}
      </Badge>
    );
  }

  return (
    <Tooltip>
      <TooltipTrigger
        render={
          <Badge variant={isAll ? "secondary" : "outline"} className="cursor-help">
            {text}
          </Badge>
        }
      />
      <TooltipContent>
        <ul className="flex flex-col gap-0.5 text-left">
          {labels.map((label) => (
            <li key={label}>{label}</li>
          ))}
        </ul>
      </TooltipContent>
    </Tooltip>
  );
}

