"use server";

import { revalidatePath } from "next/cache";
import { headers } from "next/headers";
import { z } from "zod";

import { withOrgSeatLock } from "@/features/billing/locks";
import { seatCheckErrorMessage } from "@/features/billing/messages";
import { checkRolePromotionToMember } from "@/features/billing/policy";
import {
  ActionError,
  orgAdminActionClient,
  orgInputSchema,
} from "@/lib/action-client";
import { auth } from "@/lib/server/auth";

const updateMemberRoleSchema = orgInputSchema.extend({
  orgSlug: z.string(),
  memberId: z.string(),
  role: z.enum(["member", "admin"]),
});

export const updateOrganizationMemberRole = orgAdminActionClient
  .inputSchema(updateMemberRoleSchema)
  .action(async ({ parsedInput, ctx }) => {
    const { memberId, organizationId, orgSlug, role } = parsedInput;
    const headersList = await headers();
    const targetMember = ctx.org.members.find(
      (member: any) => member.id === memberId
    );

    if (!targetMember) {
      throw new ActionError("Member not found");
    }

    const updateRole = async () => {
      if (targetMember.role !== "member" && role === "member") {
        const check = await checkRolePromotionToMember({
          orgId: organizationId,
        });
        if (!check.allowed) {
          throw new ActionError(seatCheckErrorMessage(check, "role_change"));
        }
      }

      await auth.api.updateMemberRole({
        headers: headersList,
        body: {
          memberId,
          organizationId,
          role,
        },
      });
    };

    if (targetMember.role !== "member" && role === "member") {
      await withOrgSeatLock(organizationId, updateRole);
    } else {
      await updateRole();
    }

    revalidatePath(`/org/${orgSlug}`, "layout");
    revalidatePath(`/org/${orgSlug}/people`);

    return { success: true };
  });

const removeMemberSchema = orgInputSchema.extend({
  orgSlug: z.string(),
  memberId: z.string(),
});

export const removeOrganizationMember = orgAdminActionClient
  .inputSchema(removeMemberSchema)
  .action(async ({ parsedInput, ctx }) => {
    const { memberId, organizationId, orgSlug } = parsedInput;
    const headersList = await headers();
    const targetMember = ctx.org.members.find(
      (member: any) => member.id === memberId
    );

    if (!targetMember) {
      throw new ActionError("Member not found");
    }

    await auth.api.removeMember({
      headers: headersList,
      body: {
        memberIdOrEmail: memberId,
        organizationId,
      },
    });

    revalidatePath(`/org/${orgSlug}`, "layout");
    revalidatePath(`/org/${orgSlug}/people`);

    return { success: true };
  });

