import { PortalSidebar } from "@/components/portal-sidebar";
import { Badge } from "@/components/ui/badge";
import { SidebarInset, SidebarTrigger } from "@/components/ui/sidebar";
import { getOrganizationBilling } from "@/features/billing/mirror";
import { getPlanKind, type PlanKind } from "@/features/billing/plan-kind";
import type { BillingState } from "@/features/billing/schemas";
import { getOrganizationVolumes } from "@/features/generation";
import { getOrganizationVolumeDisplayNameMap } from "@/features/volume/display-names";
import { getUserVolumeAccess } from "@/features/volume-access/queries";
import { auth } from "@/lib/server/auth";
import {
  getCachedFullOrganization,
  getCachedListOrganizations,
  getRequiredCurrentUser,
} from "@/lib/server/session";

export default async function OrgLayout({
  children,
  params,
}: {
  children: React.ReactNode;
  params: Promise<{ orgSlug: string }>;
}) {
  const { orgSlug } = await params;

  // Session freshness must be re-verified here — parent (portal) layout is
  // preserved across child segment navigation per App Router semantics, so
  // its gate does NOT re-run on org switch. Trusting it for "session existed
  // at some prior render" would 403 on session expiry.
  const user = await getRequiredCurrentUser();

  const org = await getCachedFullOrganization(orgSlug);
  if (!org) {
    notFound();
  }

  const currentMember = org.members.find((m: any) => m.userId === user.id);
  if (!currentMember) {
    forbidden();
  }

  // Side effect: keep session's activeOrganizationId in sync with the URL.
  // URL is the source of truth for render (P1); this write is for downstream
  // Better Auth plugins / queries that need an "active org" without a param.
  await auth.api.setActiveOrganization({
    body: { organizationId: org.id, organizationSlug: org.slug },
    headers: await headers(),
  });

  const isPlatformAdmin = user.role === "admin";
  const isOrgAdmin =
    currentMember.role === "owner" || currentMember.role === "admin";
  const isAdmin = isPlatformAdmin || isOrgAdmin;
  const isOwner = currentMember.role === "owner";

  const activeOrg = { id: org.id, name: org.name, slug: org.slug };

  // Parallel data fetch for the sidebar render. All consumers are inside the
  // shell, so per P4 they go through cached helpers where multiple call sites
  // exist; the rest are single-call here and can stay uncached for now.
  //
  // `listOrganizations` is degraded to `[]` on failure: the dropdown is a
  // non-critical enhancement — its data source shouldn't be a critical-path
  // dependency that 500s the whole org page. The trigger button still renders
  // the active org from `getCachedFullOrganization` above.
  const [orgsRaw, volumesRaw, memberAccess, billing] = await Promise.all([
    getCachedListOrganizations().catch((err) => {
      console.error("Failed to list organizations for switcher", err);
      return [];
    }),
    getOrganizationVolumes(org.id),
    isAdmin
      ? Promise.resolve(null)
      : getUserVolumeAccess({ userId: user.id, organizationId: org.id }),
    getOrganizationBilling(org.id),
  ]);

  const sidebarOrgs = orgsRaw.map((o: any) => ({
    id: o.id,
    name: o.name,
    slug: o.slug,
  }));

  const accessibleVolumes = memberAccess
    ? volumesRaw.filter((v) => memberAccess.includes(v.id))
    : volumesRaw;
  const volumeNameMap = await getOrganizationVolumeDisplayNameMap(
    accessibleVolumes
  );
  const sidebarVolumes = accessibleVolumes.map((v) => ({
    id: v.id,
    volumeName: volumeNameMap.get(v.id) ?? v.label,
    status: v.status,
    generationJobId: v.generationJobId,
  }));

  const billingState: BillingState | null =
    (billing?.billingState as BillingState | null) ?? null;
  const planKind: PlanKind = getPlanKind(billing);

  const sidebarUser = {
    id: user.id,
    name: user.name,
    email: user.email,
    image: user.image,
  };

  return (
    <>
      <PortalSidebar
        orgs={sidebarOrgs}
        activeOrg={activeOrg}
        isAdmin={isAdmin}
        isOwner={isOwner}
        billingState={billingState}
        planKind={planKind}
        volumes={sidebarVolumes}
        user={sidebarUser}
      />
      <SidebarInset>
        <header className="flex h-14 shrink-0 items-center gap-2 border-b px-4">
          <SidebarTrigger className="-ml-1" />
          {isAdmin &&
            planKind !== "internal" &&
            planKind !== "unknown" &&
            billingState &&
            (billingState === "past_due" ||
              billingState === "requires_action") && (
              <Badge
                variant="outline"
                className={
