import {
  getCachedFullOrganization,
  getRequiredCurrentUser,
} from "@/lib/server/session";

/**
 * Admin gate for the (admin) route group.
 *
 * Each independently-renderable boundary fresh-checks session
 * (App Router preserves parent layouts across navigation, so a parent's
 * gate may be stale by the time this layout re-runs). Org membership is
 * structural — once granted, doesn't change mid-session — so we trust the
 * parent [orgSlug] layout for it. This layer adds only the incremental
 * admin/owner role check (with platform-admin bypass), mirroring
 * orgAdminActionClient.
 *
 * `getCachedFullOrganization` is a cache hit here (parent layout already
 * called it with the same slug in this render pass).
 */
export default async function AdminLayout({
  children,
  params,
}: {
  children: React.ReactNode;
  params: Promise<{ orgSlug: string }>;
}) {
  const { orgSlug } = await params;

  const user = await getRequiredCurrentUser();
  const org = await getCachedFullOrganization(orgSlug);
  const member = org?.members.find((m: any) => m.userId === user.id);

  if (!member) {
    forbidden();
  }

  const isPlatformAdmin = user.role === "admin";
  const isOrgAdmin = member.role === "owner" || member.role === "admin";
  if (!isPlatformAdmin && !isOrgAdmin) {
    forbidden();
  }

  return <>{children}</>;
}

