     6	// stored state to this projection.
     7	export function effectiveTransferStatus(
     8	  transfer: { status: string; expiresAt: Date },
     9	  now: Date = new Date(),
    10	): TransferStatus {
    11	  if (transfer.status === "pending" && now > transfer.expiresAt) {
